// Validate shared secret
var secret = env.get('NODE_RED_SECRET');
var incoming = msg.req.headers['x-internal-secret'];

// If NODE_RED_SECRET is not configured in this Node-RED instance, allow through
// (useful during local dev – set the env var in production)
if (!secret) {
    node.warn('[TaskFlow] NODE_RED_SECRET not set in Node-RED env – skipping auth check');
    node.send([msg, null]);
    return;
}

if (incoming !== secret) {
    msg.statusCode = 403;
    msg.payload = { error: 'Forbidden' };
    node.send([null, msg]);
    return;
}

node.send([msg, null]);

var data = msg.payload;

// Choose colour + emoji based on event type
var eventConfig = {
    task_created:   { color: 0x00D4FF, emoji: '🆕', label: 'New Task Created' },
    task_completed: { color: 0x22C55E, emoji: '✅', label: 'Task Completed' },
    task_updated:   { color: 0xF59E0B, emoji: '✏️', label: 'Task Updated' }
};
var cfg = eventConfig[data.event] || { color: 0x94A3B8, emoji: '📋', label: data.event };

var embed = {
    embeds: [{
        title:       cfg.emoji + ' ' + cfg.label,
        description: '**' + (data.taskTitle || 'Untitled') + '**',
        color:       cfg.color,
        fields: [
            {
                name:   '👥 Team',
                value:  data.teamName || 'Unknown',
                inline: true
            },
            {
                name:   '👤 By',
                value:  data.actorName || 'Unknown',
                inline: true
            },
            {
                name:   '⏰ Time',
                value:  new Intl.DateTimeFormat('en-GB', { timeZone: 'Asia/Bangkok', dateStyle: 'medium', timeStyle: 'medium' }).format(new Date(data.timestamp)) + ' (ICT)',
                inline: false
            }
        ],
        footer: { text: 'TaskFlow • Smart Task System' },
        timestamp: data.timestamp
    }]
};

if (data.assignedTo) {
    embed.embeds[0].fields.splice(2, 0, {
        name:   '📌 Assigned To',
        value:  data.assignedTo,
        inline: true
    });
}

msg.webhookUrl = data.webhookUrl;
msg.payload    = embed;
return msg;

// Discord returns 204 No Content on success
var status = msg.statusCode;
if (status >= 200 && status < 300) {
    node.log('[TaskFlow] Discord webhook delivered, status=' + status);
    node.send([msg, null]);
} else {
    node.warn('[TaskFlow] Discord returned error status=' + status + ' body=' + JSON.stringify(msg.payload));
    node.send([null, msg]);
}

msg.statusCode = 200;
msg.payload    = { success: true, message: 'Notification sent' };
return msg;

msg.statusCode = 403;
msg.payload    = { success: false, error: 'Forbidden' };
return msg;
